+        "task" => "\u{2705}",     // ✅
+        "epic" => "\u{1f3c6}",    // 🏆
+        "chore" => "\u{1f9f9}",   // 🧹
+        "docs" => "\u{1f4da}",    // 📚
+        "question" => "\u{2753}", // ❓
+        _ => "\u{1f4cb}",         // 📋
+    }
 }

