+            content.append_styled("Skipped ", theme.dimmed.clone());
+            content.append_styled(&item.id, theme.emphasis.clone());
+            content.append(": ");
+            content.append_styled(&item.reason, theme.dimmed.clone());
+            content.append("\n");
