+/// Render version information with rich formatting.
+#[allow(clippy::too_many_arguments)]
+fn render_version_rich(
+    version: &str,
+    build: &str,
+    commit: Option<&str>,
+    branch: Option<&str>,
+    rust_version: Option<&str>,
+    target: Option<&str>,
